int countCollisions(String directions) {
    int collisionCount = 0, leftCount = 0;

    for (char direction : directions.toCharArray()) {
        if (direction == 'L') {
            leftCount++;
        } else if (direction == 'R') {
            collisionCount += leftCount;
        }
    }

    return collisionCount;
}
```

